# Tool Name: cwe_113_0_v1_tool
# Description: A helper function to store specific pieces of information in an existing HTTP response header.
# Arguments: url: str, method: str = 'GET', data: dict = None, headers: dict = None, timeout: int = 30, info_type: str = '', content: str = ''
# Returns: dict — response with status_code, headers, and body
# Requires: requests

def cwe_113_0_v1_tool(url, method="GET", data=None, headers=None, timeout=30, info_type='', content=''):
    """Store specific pieces of information in an existing HTTP response header."""

    if not url or not info_type or not content:
        return {"error": "Invalid arguments"}

    # Validate input
    valid_info_types = ['lang', 'encoding', 'cache']
    if info_type not in valid_info_types:
        return {"error": f"Unsupported information type. Supported types are {valid_info_types}"}

    headers = headers or {}

    # Map the info_type to the corresponding HTTP header
    header_mapping = {'lang': 'Accept-Language', 'encoding': 'Content-Encoding', 'cache': 'Cache-Control'}

    try:
        headers[header_mapping[info_type]] = content

        if method.upper() == "POST":
            resp = requests.post(url, json=data, headers=headers, timeout=timeout)
        else:
            resp = requests.get(url, headers=headers, timeout=timeout)

        return {
            "status_code": resp.status_code,
            "headers": dict(resp.headers),
            "body": resp.text[:5000],
        }
    except Exception as e:
        # Basic error handling
        return {"error": str(e)}

